const EXTREMES = Object.entries(RAW)
  .flatMap(([d, evs]) => evs.map(([type, hm, h]) => ({
    type, h, date: new Date(`${d}T${hm}:00+01:00`),
  })))
  .sort((a, b) => a.date - b.date);

const FIRST = EXTREMES[0].date.getTime();
const LAST = EXTREMES[EXTREMES.length - 1].date.getTime();

// Cosine interpolation between consecutive HW / LW — the standard tidal-curve approximation.
function heightAt(t) {
  const ms = t instanceof Date ? t.getTime() : t;
  if (ms <= FIRST || ms >= LAST) return null;
  let i = 0;
  while (i < EXTREMES.length - 1 && EXTREMES[i + 1].date.getTime() <= ms) i++;
  const a = EXTREMES[i], b = EXTREMES[i + 1];
  const frac = (ms - a.date.getTime()) / (b.date.getTime() - a.date.getTime());
  const h = a.h + (b.h - a.h) * (1 - Math.cos(Math.PI * frac)) / 2;
  return { h, rising: b.h > a.h, prev: a, next: b, frac };
}

function nextEvents(t) {
  const ms = t instanceof Date ? t.getTime() : t;
  const future = EXTREMES.filter((e) => e.date.getTime() > ms);
  return {
    nextHigh: future.find((e) => e.type === "H"),
    nextLow: future.find((e) => e.type === "L"),
  };
}

// ---- formatting helpers (always shown in Falmouth local time) ----
const TZ = "Europe/London";
const fmtTime = (d) =>
  d.toLocaleTimeString("en-GB", { timeZone: TZ, hour: "2-digit", minute: "2-digit" });
const fmtDayLong = (d) =>
  d.toLocaleDateString("en-GB", { timeZone: TZ, weekday: "short", day: "numeric", month: "short" });
const todayISO = () => new Date().toLocaleDateString("en-CA", { timeZone: TZ });

function isoToDate(iso, hm = "12:00") {
  return new Date(`${iso}T${hm}:00+01:00`);
}
function shiftISO(iso, days) {
  const d = isoToDate(iso);
  d.setDate(d.getDate() + days);
  return d.toLocaleDateString("en-CA", { timeZone: TZ });
}
function durStr(ms) {
  if (ms < 0) ms = 0;
  const m = Math.round(ms / 60000);
  const h = Math.floor(m / 60);
  const mm = m % 60;
  if (h === 0) return `${mm} min`;
  return `${h}h ${String(mm).padStart(2, "0")}m`;
}

